app.get('/api/current-version', (req, res) => {
    res.json(versionInfo);
});

app.get('/api/check-update', (req, res) => {
    const remoteUrl = versionInfo.remoteRepo;
    if (!remoteUrl || remoteUrl.includes("SEU_USUARIO")) {
        return res.json({ updateAvailable: false, message: "Repositório remoto não configurado." });
    }

    https.get(remoteUrl, { headers: { 'User-Agent': 'SisFila-Updater' } }, (response) => {
        let data = '';
        response.on('data', (chunk) => data += chunk);
        response.on('end', () => {
            try {
                const remoteVersion = JSON.parse(data);
                const hasUpdate = remoteVersion.version !== versionInfo.version;
                res.json({
                    updateAvailable: hasUpdate,
                    currentVersion: versionInfo.version,
                    remoteVersion: remoteVersion.version,
                    zipUrl: remoteVersion.zipUrl
                });
            } catch (e) {
                res.status(500).json({ updateAvailable: false, message: "Erro ao ler versão remota." });
            }
        });
    }).on('error', (err) => {
        res.status(500).json({ updateAvailable: false, message: "Erro de conexão com servidor de update." });
    });
});

app.post('/api/perform-update', async (req, res) => {
    const { zipUrl } = req.body;
    if (!zipUrl) return res.status(400).json({ success: false, message: "URL do ZIP não fornecida." });

    const tempZip = path.join(userDataPath, 'update.zip');
    const extractPath = path.join(userDataPath, 'update_temp');

    console.log(`[UPDATE] Iniciando download: ${zipUrl}`);

    const file = fs.createWriteStream(tempZip);
    https.get(zipUrl, { headers: { 'User-Agent': 'SisFila-Updater' } }, (response) => {
        if (response.statusCode === 301 || response.statusCode === 302) {
            https.get(response.headers.location, { headers: { 'User-Agent': 'SisFila-Updater' } }, (res2) => res2.pipe(file));
        } else {
            response.pipe(file);
        }

        file.on('finish', () => {
            file.close(async () => {
                console.log("[UPDATE] Download concluído. Extraindo...");

                let command = '';
                if (os.platform() === 'win32') {
                    command = `powershell -Command "Expand-Archive -Path '${tempZip}' -DestinationPath '${extractPath}' -Force"`;
                } else {
                    command = `unzip -o "${tempZip}" -d "${extractPath}"`;
                }

                exec(command, (err) => {
                    if (err) {
                        console.error("[UPDATE] Erro na extração:", err);
                        return res.status(500).json({ success: false, message: "Falha ao extrair arquivos." });
                    }

                    console.log("[UPDATE] Extração concluída. Substituindo arquivos e reiniciando...");

                    // Nota: No GitHub, o ZIP vem com uma pasta raiz (ex: sisfila-main/)
                    // Este script assume que o usuário vai copiar os conteúdos manualmente ou que o serviço reiniciará
                    // Para um update robusto, o ideal é um script .bat ou .sh externo que mova os arquivos.

                    res.json({ success: true, message: "Arquivos baixados. O sistema irá reiniciar em 5 segundos." });

                    setTimeout(() => {
                        console.log("[UPDATE] Encerrando processo para reinicialização...");
                        process.exit(0); 
                    }, 5000);
                });
            });
        });
    }).on('error', (err) => {
        res.status(500).json({ success: false, message: "Erro no download do update." });
    });
});

