    `);
    const result = await db.get("SELECT count(*) as c FROM users");
    if (result.c === 0) {
        await db.run("INSERT INTO services (id, name, active) VALUES (?, ?, ?)", ['1', 'Comercial', 1]);
        await db.run("INSERT INTO users (id, name, username, password, deskNumber, serviceId, role, active) VALUES (?, ?, ?, ?, ?, ?, ?, ?)", ['u1', 'Admin', 'admin', 'admin', '01', '1', 'admin', 1]);
