        await setConfig('systemInfo', { installDate: Date.now(), licenseKey: null, clientName: '', clientLogo: '' });
    }
}

async function getConfig(key) {
    if (!db) return null;
    const row = await db.get("SELECT value FROM config WHERE key = ?", [key]);
