const DEFAULT_TICKET_TEMPLATE = `<html><head><style>@page { margin: 0; } body { margin: 0; padding: 5px; font-family: 'Arial', sans-serif; text-align: center; color: black; } h2, .label, .password, .info, .meta, .extra1 { text-align: center; } .logo { max-width: 80%; max-height: 60px; margin-bottom: 5px; } h2 { font-size: 14px; margin: 2px 0; text-transform: uppercase; } .divider { border-top: 1px dashed black; margin: 5px 0; width: 100%; } .label { font-size: 12px; font-weight: bold; margin-top: 5px; } .password { font-size: {{FONT_SIZE_PX}}px; font-weight: 900; margin: 5px 0; line-height: 1; } .info { font-size: 16px; font-weight: bold; margin: 2px 0; } .meta { font-size: 10px; margin-top: 10px; } .extra1 { font-size: 10px; margin-top: 10px; }</style></head><body>{{LOGO}}<h2>{{EMPRESA}}</h2><div class="divider"></div><div class="label">SENHA</div><div class="password">{{SENHA}}</div><div class="extra1">Serviço solicitado</div><div class="info">{{SERVICO}}</div><div class="extra1">Tipo de atendimento</div><div class="info">{{PRIORIDADE}}</div><div class="divider"></div><div class="meta">{{DATA}} - {{HORA}}</div><br/><br/></body></html>`;

function downloadWithRedirects(url, dest, cb) {
  let options;
  try {
    const urlObj = new URL(url);
    options = { hostname: urlObj.hostname, path: urlObj.pathname + urlObj.search, protocol: urlObj.protocol, headers: { 'User-Agent': 'Mozilla/5.0' } };
  } catch (e) { if (cb) cb(e); return; }
  https.get(options, (response) => {
    if ([301, 302, 307, 308].includes(response.statusCode) && response.headers.location) { downloadWithRedirects(response.headers.location, dest, cb); return; }
    const file = fs.createWriteStream(dest);
    response.pipe(file);
    file.on('finish', () => { file.close(() => { if (cb) cb(null); }); });
  }).on('error', cb);
}

function ensureSumatra() {
  if (!fs.existsSync(SUMATRA_EXE)) {
    downloadWithRedirects("https://files2.sumatrapdfreader.org/software/sumatrapdf/rel/3.5.2/SumatraPDF-3.5.2-64.exe", SUMATRA_EXE, (err) => { if (!err) console.log("SumatraPDF pronto."); });
  }
}

function validateLicenseKey(key, name, email) {
  if (!key) return false;
  const parts = key.split('-');
  if (parts.length !== 3 || parts[0] !== 'SIS') return false;
  const expiryHex = parts[1];
  const signature = parts[2];
  const payload = `${(name || '').trim().toLowerCase()}|${(email || '').trim().toLowerCase()}|${expiryHex}`;
  const expectedSignature = crypto.createHmac('sha256', SECRET_KEY).update(payload).digest('hex').substring(0, 12).toUpperCase();
  return signature === expectedSignature;
}

