app.get('/api/license', async (req, res) => {
    const systemInfo = (await getConfig('systemInfo')) || {};
    const now = Date.now();
    const isValid = validateLicenseKey(systemInfo.licenseKey, systemInfo.clientName, systemInfo.clientEmail);
    let trialDaysLeft = 0;
    let licenseExpiryDate = null;
    if (isValid && systemInfo.licenseKey) {
        licenseExpiryDate = parseInt(systemInfo.licenseKey.split('-')[1], 36);
        trialDaysLeft = Math.ceil((licenseExpiryDate - now) / 86400000);
    } else {
        trialDaysLeft = 30 - Math.ceil(Math.abs(now - (systemInfo.installDate || now)) / 86400000);
    }
    const isBlocked = (trialDaysLeft <= 0) && (!isValid || (licenseExpiryDate && now > licenseExpiryDate));
    res.json({ ...systemInfo, trialDaysLeft: Math.max(0, trialDaysLeft), licenseExpiryDate, isBlocked, hasLicense: isValid && (!licenseExpiryDate || now <= licenseExpiryDate) });
});

