app.post('/api/print-ticket', async (req, res) => {
    const { displayId, serviceName, priority, createdAt, fontSize } = req.body;
    const printerConfig = await getConfig('printerConfig') || {};
    const systemInfo = await getConfig('systemInfo') || {};
    if (!printerConfig.printerName) return res.status(400).json({ success: false });
    const scale = parseInt(fontSize || printerConfig.fontSize) || 2;
    const widthMm = parseInt(String(printerConfig.paperWidth).replace(/\D/g, '')) || 80;
    let rawHtml = printerConfig.ticketTemplate || DEFAULT_TICKET_TEMPLATE;
    const map = { '{{LOGO}}': systemInfo.clientLogo ? `<img src="${systemInfo.clientLogo}" class="logo" />` : '', '{{EMPRESA}}': systemInfo.clientName || 'SISFILA', '{{SENHA}}': displayId, '{{SERVICO}}': serviceName, '{{PRIORIDADE}}': priority, '{{DATA}}': new Date(createdAt).toLocaleDateString(), '{{HORA}}': new Date(createdAt).toLocaleTimeString([], {hour:'2-digit', minute:'2-digit'}), '{{FONT_SIZE_PX}}': 40 + (scale * 10) };
    for (const [k, v] of Object.entries(map)) rawHtml = rawHtml.replace(new RegExp(k, 'g'), v);
    try {
        const browser = await puppeteer.launch();
        const page = await browser.newPage();
        await page.setContent(rawHtml);
        await page.pdf({ path: TEMP_PDF_FILE, width: `${widthMm}mm`, printBackground: true });
        await browser.close();
        exec(`"${SUMATRA_EXE}" -print-to "${printerConfig.printerName}" -silent "${TEMP_PDF_FILE}"`, () => { try { fs.unlinkSync(TEMP_PDF_FILE); } catch(e) {} });
        res.json({ success: true });
    } catch(err) { res.status(500).json({ success: false }); }
});

