            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ zipUrl: updateInfo.zipUrl })
        });
        const data = await res.json();
        if (data.success) {
            alert(data.message);
            setStatus('done');
        } else alert(data.message);
    } catch (e) {
        alert("Erro ao realizar atualização.");
        setStatus('idle');
    }
  };

  return (
    <div className="flex flex-col md:flex-row h-[450px]">
        <div className="md:w-40 border-b md:border-b-0 md:border-r border-slate-200 dark:border-slate-700 p-2 flex flex-row md:flex-col gap-1 overflow-x-auto">
           {[
               {id:'general', icon:Cpu, l:'Geral'},
               {id:'update', icon:RefreshCw, l:'Atualização'},
               {id:'printer', icon:Printer, l:'Impressão'},
               {id:'layout', icon:LayoutTemplate, l:'Layout'},
               {id:'license', icon:Key, l:'Licença'}
           ].map(t => (
               <button key={t.id} onClick={() => setSubTab(t.id as any)} className={`px-3 py-2 text-left rounded-md text-xs font-bold flex items-center gap-2 ${subTab === t.id ? 'bg-indigo-50 dark:bg-indigo-900/30 text-indigo-600 dark:text-indigo-400' : 'text-slate-600 dark:text-slate-400 hover:bg-slate-100 dark:hover:bg-slate-800'}`}>
                 <t.icon size={14} /> {t.l}
               </button>
           ))}
        </div>
        <div className="flex-1 p-4 overflow-y-auto">
            {subTab === 'update' && (
                <div className="space-y-6 animate-fade-in max-w-md">
                    <h3 className="text-sm font-bold text-slate-900 dark:text-white mb-3 flex items-center gap-2"><RefreshCw size={16} className="text-indigo-500"/> Atualização de Software</h3>
                    <div className="p-4 bg-slate-50 dark:bg-slate-900/50 border border-slate-200 dark:border-slate-700 rounded-xl">
                        <p className="text-xs text-slate-500 uppercase font-bold mb-1">Versão Instalada</p>
                        <p className="text-xl font-black text-slate-800 dark:text-white">{currentVer?.version || '---'}</p>
                    </div>

                    {!updateInfo ? (
                        <button onClick={handleCheckUpdate} disabled={status === 'checking'} className="w-full bg-indigo-600 hover:bg-indigo-500 text-white font-bold py-2 rounded text-sm flex justify-center items-center gap-2">
                           {status === 'checking' ? <RefreshCw size={16} className="animate-spin" /> : <RefreshCw size={16} />} 
                           Verificar Atualizações
                        </button>
                    ) : updateInfo.updateAvailable ? (
                        <div className="p-4 bg-emerald-50 dark:bg-emerald-900/20 border border-emerald-200 dark:border-emerald-800 rounded-xl animate-bounce">
                            <p className="text-emerald-800 dark:text-emerald-400 font-bold text-sm mb-2">Nova versão disponível: {updateInfo.remoteVersion}</p>
                            <button onClick={handlePerformUpdate} disabled={status === 'updating'} className="w-full bg-emerald-600 hover:bg-emerald-500 text-white font-bold py-2 rounded text-sm flex justify-center items-center gap-2">
                                {status === 'updating' ? <RefreshCw size={16} className="animate-spin" /> : <Download size={16} />}
                                Atualizar Agora
                            </button>
                        </div>
                    ) : (
                        <div className="p-4 bg-slate-100 dark:bg-slate-800/50 border border-slate-200 dark:border-slate-700 rounded-xl flex items-center gap-2">
                            <CheckCircle size={16} className="text-emerald-500" />
                            <p className="text-xs font-bold text-slate-600 dark:text-slate-400">Você já possui a versão mais recente.</p>
                        </div>
                    )}
                </div>
            )}
            {subTab === 'general' && (
                <div className="space-y-6 animate-fade-in max-w-sm">
                    <h3 className="text-sm font-bold text-slate-900 dark:text-white mb-3 flex items-center gap-2"><Database size={16} className="text-indigo-500"/> Banco de Dados</h3>
                    <button onClick={() => window.location.href = '/api/backup-db'} className="w-full bg-blue-600 hover:bg-blue-500 text-white py-2 rounded text-sm font-bold flex items-center justify-center gap-2"><Download size={16} /> Baixar Backup</button>
                    <div className="border-t border-slate-200 dark:border-slate-700 pt-4">
                        <h3 className="text-xs font-bold text-red-600 dark:text-red-400 mb-2 flex items-center gap-1 uppercase"><AlertOctagon size={12}/> Zona de Perigo</h3>
                        <button onClick={onResetSystem} className="bg-red-50 text-red-600 border border-red-200 hover:bg-red-100 py-2 rounded text-xs font-bold w-full">Zerar Sistema</button>
                    </div>
                </div>
            )}
            {subTab === 'printer' && <PrinterTab />}
            {subTab === 'layout' && <LayoutTab />}
            {subTab === 'license' && <LicenseTab />}
        </div>
    </div>
  );
};

